import sqlite3
import os

DB_NAME = "database.db"

if os.path.exists(DB_NAME):
    os.remove(DB_NAME)
    print("Старая база данных удалена.")

conn = sqlite3.connect(DB_NAME)
cursor = conn.cursor()

# Таблицы
cursor.execute("""
CREATE TABLE users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    password TEXT NOT NULL,
    email TEXT
)
""")

cursor.execute("""
CREATE TABLE movies (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    title TEXT NOT NULL,
    description TEXT,
    release_year INTEGER,
    country TEXT,
    director TEXT,
    cast TEXT,
    duration INTEGER,
    kinopoisk_rating REAL,
    poster_url TEXT,
    type TEXT DEFAULT 'movie',
    status TEXT DEFAULT 'released',
    seasons INTEGER,
    episodes INTEGER
)
""")

cursor.execute("""
CREATE TABLE genres (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT UNIQUE NOT NULL
)
""")

cursor.execute("""
CREATE TABLE movie_genres (
    movie_id INTEGER,
    genre_id INTEGER,
    FOREIGN KEY (movie_id) REFERENCES movies(id),
    FOREIGN KEY (genre_id) REFERENCES genres(id),
    PRIMARY KEY (movie_id, genre_id)
)
""")

cursor.execute("""
CREATE TABLE ratings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    movie_id INTEGER,
    rating INTEGER CHECK(rating >= 1 AND rating <= 5),
    UNIQUE(user_id, movie_id),
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (movie_id) REFERENCES movies(id)
)
""")

cursor.execute("""
CREATE TABLE reviews (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    movie_id INTEGER,
    review_text TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (movie_id) REFERENCES movies(id)
)
""")

cursor.execute("""
CREATE TABLE user_movies (
    user_id INTEGER,
    movie_id INTEGER,
    watched BOOLEAN DEFAULT 0,
    liked BOOLEAN DEFAULT 0,
    want_to_watch BOOLEAN DEFAULT 0,
    PRIMARY KEY (user_id, movie_id),
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (movie_id) REFERENCES movies(id)
)
""")

cursor.execute("""
CREATE TABLE playlists (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    name TEXT NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    is_public BOOLEAN DEFAULT 0,
    FOREIGN KEY (user_id) REFERENCES users(id)
)
""")

cursor.execute("""
CREATE TABLE playlist_movies (
    playlist_id INTEGER,
    movie_id INTEGER,
    added_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (playlist_id, movie_id),
    FOREIGN KEY (playlist_id) REFERENCES playlists(id),
    FOREIGN KEY (movie_id) REFERENCES movies(id)
)
""")

cursor.execute("""
CREATE TABLE friends (
    user_id INTEGER,
    friend_id INTEGER,
    status TEXT DEFAULT 'pending',
    PRIMARY KEY (user_id, friend_id),
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (friend_id) REFERENCES users(id)
)
""")

cursor.execute("""
CREATE TABLE playlist_access (
    playlist_id INTEGER,
    user_id INTEGER,
    PRIMARY KEY (playlist_id, user_id),
    FOREIGN KEY (playlist_id) REFERENCES playlists(id),
    FOREIGN KEY (user_id) REFERENCES users(id)
)
""")

# Жанры
genre_names = ['Боевик', 'Драма', 'Комедия', 'Фантастика', 'Ужасы', 'Триллер', 'Мелодрама', 'Фэнтези', 'Приключения', 'Детектив', 'Криминал', 'Исторический', 'Военный', 'Спорт', 'Мюзикл', 'Вестерн', 'Биография', 'Анимация', 'Семейный']
genre_map = {}
for name in genre_names:
    cursor.execute("INSERT INTO genres (name) VALUES (?)", (name,))
    genre_map[name] = cursor.lastrowid

# Функция добавления фильма
def add_movie(title, desc, year, country, director, cast, duration, kp_rating, poster_url, genres_str,
              mtype="movie", status="released", seasons=None, episodes=None):
    cursor.execute("""
        INSERT INTO movies (title, description, release_year, country, director, cast, duration,
                           kinopoisk_rating, poster_url, type, status, seasons, episodes)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    """, (title, desc, year, country, director, cast, duration, kp_rating, poster_url, mtype, status, seasons, episodes))
    movie_id = cursor.lastrowid
    for g in genres_str.split(","):
        g = g.strip()
        if g in genre_map:
            cursor.execute("INSERT INTO movie_genres (movie_id, genre_id) VALUES (?, ?)", (movie_id, genre_map[g]))

